1	import * as THREE from "three";
2	import { createTerrain } from "./terrain.js";
3	import { createFirstPerson } from "./firstPerson.js";
4	import { createOverhead } from "./overhead.js";
5	import { makeBeamTexture, makeIceBlock, makeIdSprite } from "./memoryProps.js";
6	
7	// LEVEL 2 ("The Drone Bay") — the same island, revisited.
8	//
9	// The day-to-day agentic loop, played: delegate → review → accept.
10	// Five ship systems are dark; five drones can fix them in parallel while you
11	// can only be in one place. One new command on top of what L1 taught:
12	//
13	//   walk to a dark system, press E      → a drone takes the job, you're free
14	//   the drone finishes while you're away → its work seals under a checkpoint
15	//   walk up → `entire checkpoint explain <id>` is PRE-FILLED — press Enter
16	//   read what it actually did            → ADD TO SHIP (Y) → system online
17	//   the FIFTH accept keeps the terminal open: type `entire dispatch` right
18	//   there — the day's report writes itself from the checkpoints. Finish line.
19	//
20	// Drones don't repair — they IMPROVISE (a bent dish comes back as a signal
21	// spire). The transformation is what makes you NEED the explanation.
22	//
23	// PRESSURE: one countdown. Watching one drone at a time can't beat the clock;
24	// running the whole fleet in parallel can. Nothing forces it — the math does.
25	
26	const INTERACT_DIST = 8;     // how close (XZ) to assign / review a site
27	const CONSOLE_DIST = 9;      // how close (XZ) to open the ship terminal
28	const TOTAL_TIME = 150;      // seconds for the whole run (tunable)
29	const WORK_TIME = 18;        // seconds a drone spends fixing a system
30	const LOW_TIME = 45;         // clock turns urgent under this
31	const CRIT_TIME = 15;        // clock goes CRITICAL under this
32	const PANIC_TIME = 45;       // the SKY starts shifting toward panic-red
33	const DRONE_SPEED = 26;      // world units / second in flight
34	const MELT_DUR = 1.2;        // seconds the ice takes to melt on ADD TO SHIP
35	
36	// Sky panic palette — same dread as Level 1's clock.
37	const SKY_CALM  = new THREE.Color(0x2a2350);
38	const SKY_PANIC = new THREE.Color(0x6e0f16);
39	const FOG_PANIC = new THREE.Color(0x4a0a0e);
40	const DOME_CALM = new THREE.Color(0x3a3168);
41	const DOME_PANIC = new THREE.Color(0x7a141c);
42	const SUN_CALM  = new THREE.Color(0xfff1dc);
43	const SUN_PANIC = new THREE.Color(0xff5a3c);
44	
45	const CONSOLE_POS = { x: -6, z: 56 };
46	const BAY_ROW = { x0: -16, dx: 4, z: 50 };   // five parked drones by the console
47	
48	// The five dark systems, what the drones improvise them into, and the story
49	// each checkpoint carries. Ids are fixed so the fiction is stable across runs.
50	// Exported: Level 3 quizzes the player on this exact record, and rebuilds the
51	// upgrades on its island as the things the questions are about.
52	export const SYSTEMS = [
53	  {
54	    ckpt: "a1c9e4f72b05", name: "IGNITION COILS",
55	    pos: { x: -34, z: -28 },
56	    broken: "buildBrokenCoils", upgrade: "buildPlasmaRing",
57	    became: "Plasma Ring",
58	    card: [
59	      ["subagent", "subagent-1"],
60	      ["system", "ignition coils"],
61	      ["did", "coils beyond saving — rebuilt as a plasma ring from salvaged hull plate"],
62	      ["session", "2 attempts · parts scavenged: hull plate ×3"],
63	    ],
64	  },
65	  {
66	    ckpt: "3d7b0f9c61ae", name: "NAV CORE",
67	    pos: { x: 40, z: -18 },
68	    broken: "buildBrokenNav", upgrade: "buildStarDome",
69	    became: "Star Dome",
70	    card: [
71	      ["subagent", "subagent-2"],
72	      ["system", "nav core"],
73	      ["did", "core unrecoverable — remapped from scratch; starfield calibrated to the lavender belt"],
74	      ["session", "1 attempt · 412 stars plotted"],
75	    ],
76	  },
77	  {
78	    ckpt: "f25c8b30d971", name: "LONG-RANGE ANTENNA",
79	    pos: { x: 28, z: 38 },
80	    broken: "buildBrokenDish", upgrade: "buildSignalSpire",
81	    became: "Signal Spire",
82	    card: [
83	      ["subagent", "subagent-3"],
84	      ["system", "long-range antenna"],
85	      ["did", "dish unsalvageable — respun the mast into a signal spire; relay handshake at full strength"],
86	      ["session", "3 attempts · the first two fell over"],
87	    ],
88	  },
89	  {
90	    ckpt: "62e0a9d4c8f3", name: "LIFE SUPPORT",
91	    pos: { x: -30, z: 36 },
92	    broken: "buildBrokenVent", upgrade: "buildGardenPod",
93	    became: "Garden Pod",
94	    card: [
95	      ["subagent", "subagent-4"],
96	      ["system", "life support scrubbers"],
97	      ["did", "filters dead — replaced with a living filter; two vines scavenged from the crash"],
98	      ["session", "1 attempt · the vines approved"],
99	    ],
100	  },
101	  {
102	    ckpt: "8b47f1e62da0", name: "LANDING STRUTS",
103	    pos: { x: 8, z: -44 },
104	    broken: "buildBrokenStrut", upgrade: "buildGravSkid",
105	    became: "Grav Skid",
106	    card: [
107	      ["subagent", "subagent-5"],
108	      ["system", "landing struts"],
109	      ["did", "strut seized solid — swapped for grav skids; technically the ship floats now"],
110	      ["session", "2 attempts · torque spec: vibes"],
111	    ],
112	  },
113	];
114	
115	function normalizeCmd(s) {
116	  return s.trim().toLowerCase().replace(/\s+/g, " ");
117	}
118	
119	// ---------- prop builders: the broken systems ----------
120	const CHARRED = () => new THREE.MeshStandardMaterial({ color: 0x2a2e38, roughness: 0.9, metalness: 0.3 });
121	const SCORCH = () => new THREE.MeshStandardMaterial({ color: 0x3a3f4a, roughness: 0.85, metalness: 0.25 });
122	
123	function withWarnLight(g) {
124	  // A small red blinking bulb so broken things read as "broken" up close.
125	  const bulb = new THREE.Mesh(
126	    new THREE.SphereGeometry(0.22, 10, 10),
127	    new THREE.MeshStandardMaterial({ color: 0x401512, emissive: 0xff3b2e, emissiveIntensity: 1.6 })
128	  );
129	  bulb.position.y = g.userData.warnY ?? 3.2;
130	  g.add(bulb);
131	  g.userData.warn = bulb;
132	  return g;
133	}
134	function buildBrokenCoils() {
135	  const g = new THREE.Group();
136	  for (let i = 0; i < 3; i++) {
137	    const c = new THREE.Mesh(new THREE.CylinderGeometry(1.1 - i * 0.18, 1.2 - i * 0.18, 1.0, 10), i ? CHARRED() : SCORCH());
138	    c.position.y = 0.5 + i * 1.05;
139	    c.rotation.z = (i % 2 ? -1 : 1) * 0.12 * (i + 1);   // the stack leans, sadly
140	    g.add(c);
141	  }
142	  g.userData.warnY = 3.6;
143	  return withWarnLight(g);
144	}
145	function buildBrokenNav() {
146	  const g = new THREE.Group();
147	  const ped = new THREE.Mesh(new THREE.CylinderGeometry(0.9, 1.2, 1.4, 8), SCORCH());
148	  ped.position.y = 0.7;
149	  const core = new THREE.Mesh(new THREE.IcosahedronGeometry(1.5, 0), CHARRED());
150	  core.position.y = 2.6;
151	  core.rotation.set(0.4, 0.2, 0.5);
152	  g.add(ped, core);
153	  g.userData.warnY = 4.4;
154	  return withWarnLight(g);
155	}
156	function buildBrokenDish() {
157	  const g = new THREE.Group();
158	  const mast = new THREE.Mesh(new THREE.CylinderGeometry(0.18, 0.24, 3.2, 8), SCORCH());
159	  mast.position.y = 1.4;
160	  mast.rotation.z = 0.5;                                // bent over
161	  const dish = new THREE.Mesh(new THREE.CylinderGeometry(1.9, 1.5, 0.4, 12), CHARRED());
162	  dish.position.set(1.6, 0.5, 0);
163	  dish.rotation.z = 1.2;                                // face-down in the dirt
164	  g.add(mast, dish);
165	  g.userData.warnY = 3.0;
166	  return withWarnLight(g);
167	}
168	function buildBrokenVent() {
169	  const g = new THREE.Group();
170	  const box = new THREE.Mesh(new THREE.BoxGeometry(2.6, 2.0, 2.0), SCORCH());
171	  box.position.y = 1.0;
172	  for (let i = 0; i < 3; i++) {
173	    const slat = new THREE.Mesh(new THREE.BoxGeometry(2.2, 0.16, 0.1), CHARRED());
174	    slat.position.set(0, 0.6 + i * 0.5, 1.06);
175	    slat.rotation.x = 0.5;
176	    g.add(slat);
177	  }
178	  g.add(box);
179	  g.userData.warnY = 2.8;
180	  return withWarnLight(g);
181	}
182	function buildBrokenStrut() {
183	  const g = new THREE.Group();
184	  const leg = new THREE.Mesh(new THREE.BoxGeometry(0.8, 4.2, 0.8), SCORCH());
185	  leg.position.set(0, 1.6, 0);
186	  leg.rotation.z = 0.55;                                // collapsed sideways
187	  const foot = new THREE.Mesh(new THREE.CylinderGeometry(1.4, 1.6, 0.5, 10), CHARRED());
188	  foot.position.set(1.6, 0.25, 0);
189	  g.add(leg, foot);
190	  g.userData.warnY = 3.4;
191	  return withWarnLight(g);
192	}
