624	  function panicFactor() {
625	    if (failed) return 1;
626	    if (!timerRunning || timeLeft > PANIC_TIME) return 0;
627	    let p = (PANIC_TIME - timeLeft) / PANIC_TIME;
628	    p *= p;
629	    if (timeLeft <= CRIT_TIME) {
630	      const throb = 0.5 + 0.5 * Math.sin(performance.now() / 85);
631	      p += 0.14 * throb;
632	    }
633	    return Math.min(1, p);
634	  }
