990	  // ---------- per-frame ----------
991	  function update(dt, t) {
992	    fp.update(dt);
993	
994	    // Level countdown — one clock for the whole run.
995	    if (active && timerRunning && !failed && !reportSent) {
996	      timeLeft = Math.max(0, timeLeft - dt);
997	      updateClock();
998	      if (timeLeft <= 0) failLevel();
999	    }
1000	    applyPanicSky();
1001	
1002	    // Drones fly, work, and head home.
1003	    for (let i = 0; i < drones.length; i++) {
1004	      const d = drones[i];
1005	      const beam = workBeams[i];
1006	      if (d.state === "bay") {
1007	        d.model.position.y = d.home.y + Math.sin((t + d.bobOff) * 2) * 0.15;
1008	        d.model.userData.ring.rotation.z += dt * 1.2;
1009	      } else if (d.state === "flying" || d.state === "returning") {
1010	        d.t += dt;
1011	        const k = Math.min(1, d.t / d.dur);
1012	        const ease = k * k * (3 - 2 * k);
1013	        d.model.position.lerpVectors(d.from, d.to, ease);
1014	        d.model.position.y += Math.sin(k * Math.PI) * 3;   // arc over the island
1015	        d.model.userData.ring.rotation.z += dt * 6;
1016	        if (k >= 1) {
