1060	        s.beam.visible = true;
1061	      } else if (s.state === "sealed") {
1062	        s.beam.material.color.setHex(0x8fe3ff);
1063	        s.beam.material.opacity = 0.42;
1064	        s.beam.visible = true;
1065	      } else {
1066	        s.beam.visible = false;       // added — the upgrade itself is the landmark
1067	        if (s.meltT > 0) {            // the checkpoint seal melts away
1068	          s.meltT = Math.max(0, s.meltT - dt);
1069	          s.ice.material.opacity = 0.62 * (s.meltT / MELT_DUR);
1070	          if (s.meltT <= 0) s.ice.visible = false;
1071	        }
1072	        // The improvised upgrades live a little.
1073	        const anim = s.upgradeModel.userData.anim;
1074	        if (anim?.type === "ring") {
1075	          anim.ring.rotation.y += dt * 0.8;
1076	          anim.ring.position.y = 3.4 + Math.sin(t * 1.6) * 0.2;
1077	        } else if (anim?.type === "dome") {
